survivors.script:
hold_ticks := 0
if ((#TemperatureSensor #Pantry).temperatureSensor_temperature >= 25) {
hold_ticks = hold_ticks + 1
    if (hold_ticks > 1) {
(#AirConditioner #Switch #Pantry).switch_on()
        break
}
}
else {
hold_ticks = 0
}

triggered := false
if ((#Door).door_doorState == "open") {
if (triggered == false) {
        delay(100 MSEC)
all(#Light #Switch #LivingRoom).switch_on()
        triggered = true
}
}
else {
triggered = false
}

triggered := false
if ((#MotionSensor).motionSensor_motion == true) {
if (triggered == false) {
tmp = (#Light).light_currentBrightness + 10
        if (tmp > 100) {
tmp = 100
}
(#Light).light_moveToBrightness(tmp, 0)
        if ((#Light).light_currentBrightness >= 100) {
break
}
else {
}
triggered = true
}
}
else {
triggered = false
}

triggered := false
if ((#MotionSensor).motionSensor_motion == true) {
if (triggered == false) {
tmp = (#Light).light_currentBrightness + 10
        if (tmp > 100) {
tmp = 100
}
(#Light).light_moveToBrightness(tmp, 0)
        if ((#Light).light_currentBrightness <= 100) {
break
}
else {
(#Light).light_moveToBrightness((#Light).light_currentBrightness, 0)
}
triggered = true
}
}
else {
triggered = false
}

hold_ticks := 0
if ((#MotionSensor #LivingRoom).motionSensor_motion == false) {
hold_ticks = hold_ticks + 1
    if (hold_ticks > 300) {
(#Plug #Switch #LivingRoom #Strip).switch_off()
        break
}
}
else {
hold_ticks = 0
}

hold_ticks := 0
if ((#Door #FrontDoor).door_doorState == "open") {
hold_ticks = hold_ticks + 1
    if (hold_ticks > 50) {
(#Plug #Switch #Entrance #Fan).switch_on()
        break
}
}
else {
hold_ticks = 0
