if ((#PresenceSensor).presenceSensor_presence == true) {
hold_ticks = hold_ticks + 1
    if (hold_ticks > 300) {
(#Switch).switch_on()
        break
}
}
else {
hold_ticks = 0
}

hold_ticks := 0
if ((#Plug #Office #Printer).plug_power < 5) {
hold_ticks = hold_ticks + 1
    if (hold_ticks > 6000) {
(#Plug #Switch #Office #Printer).switch_off()
        break
}
}
else {
hold_ticks = 0
}

